/**
 * SPEC-020: Capturas — Sheet "Asignar empresa y contacto" (componente aislado).
 * Generated by QA Dev agent.
 *
 * Frontera de mocking: bridge window.api (listCompanies/listContacts/
 * assignInterviewCompany). El Sheet de Radix es un Dialog (portal + fondo
 * aria-hidden): las opciones de los Selects se buscan con screen, el resto
 * scopeado al Sheet. Tooltip sobre Select disabled → wrapper span tabIndex 0
 * (patrón DisabledTooltip); máximo 1 hover de tooltip por render.
 */
import { render, screen, waitFor, within, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { Toaster } from '@/components/ui/sonner'
import { TooltipProvider } from '@/components/ui/tooltip'
import { AssignCompanySheet } from '@/components/captures/AssignCompanySheet'
import type { AssignCompanyResult } from '@/types/captures'
import type { Company, Contact, Interview } from '@/types/domain'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

let mockApi: MockApiHandle
let onAssigned: ReturnType<typeof vi.fn<(result: AssignCompanyResult) => void>>
let onOpenChange: ReturnType<typeof vi.fn<(open: boolean) => void>>

const COMPANY: Company = {
  id: 'c-1',
  name: 'Acme Corp',
  website: null,
  linkedinUrl: null,
  createdAt: '2026-07-02T12:00:00.000Z',
  updatedAt: '2026-07-02T12:00:00.000Z'
}

const CONTACT: Contact = {
  id: 'ct-1',
  companyId: 'c-1',
  name: 'Jane Doe',
  position: null,
  linkedinUrl: null,
  createdAt: '2026-07-02T12:00:00.000Z',
  updatedAt: '2026-07-02T12:00:00.000Z'
}

const INTERVIEW: Interview = {
  id: 'i-1',
  discoveryId: 'd-1',
  companyId: null,
  contactIds: [],
  interviewGroupId: null,
  templateId: null,
  title: 'Captura sin empresa',
  status: 'draft',
  scriptMarkdown: null,
  objectives: [],
  wavPath: null,
  transcriptPath: null,
  createdAt: '2026-07-10T10:00:00.000Z',
  updatedAt: '2026-07-10T10:00:00.000Z'
}

function renderSheet(): RenderResult {
  return render(
    <TooltipProvider>
      <AssignCompanySheet
        open
        onOpenChange={onOpenChange}
        interview={INTERVIEW}
        discoveryName="Vertical Sanidad"
        onAssigned={onAssigned}
      />
      <Toaster />
    </TooltipProvider>
  )
}

async function findSheet(): Promise<HTMLElement> {
  return await screen.findByTestId('assign-company-sheet')
}

/** Selecciona una opción del Select "Empresa" (las opciones viven en un portal). */
async function chooseCompany(
  user: ReturnType<typeof userEvent.setup>,
  optionName: string
): Promise<void> {
  const sheet = await findSheet()
  await user.click(within(sheet).getByRole('combobox', { name: 'Empresa' }))
  await user.click(await screen.findByRole('option', { name: optionName }))
}

beforeEach(() => {
  vi.clearAllMocks()
  mockApi = installMockApi()
  onAssigned = vi.fn<(result: AssignCompanyResult) => void>()
  onOpenChange = vi.fn<(open: boolean) => void>()
  vi.mocked(mockApi.api.db.listCompanies).mockResolvedValue({ ok: true, data: [COMPANY] })
  vi.mocked(mockApi.api.db.listContacts).mockResolvedValue({ ok: true, data: [CONTACT] })
})

describe('AssignCompanySheet', () => {
  // SPEC-020 · AC-23, adaptado por SPEC-043: las empresas son globales — el
  // Sheet ofrece TODAS las empresas del sistema (listCompanies sin parámetro)
  it('offers every company in the system plus "+ Nueva empresa", and gates the contact select behind choosing a company', async () => {
    const user = userEvent.setup()
    renderSheet()

    const sheet = await findSheet()
    // Descripción con el discovery de la captura
    expect(sheet).toHaveTextContent(
      'La captura se moverá a la empresa dentro de su discovery «Vertical Sanidad».'
    )

    // Contacto deshabilitado con Tooltip hasta elegir empresa
    const contactSelect = within(sheet).getByRole('combobox', { name: 'Contacto' })
    expect(contactSelect).toBeDisabled()
    const tooltipTrigger = contactSelect.closest('span[tabindex="0"]')
    if (tooltipTrigger === null) {
      throw new Error('El Select de contacto disabled debe envolverse en el trigger del Tooltip')
    }
    await user.hover(tooltipTrigger)
    const hints = await screen.findAllByText('Selecciona primero una empresa')
    expect(hints.length).toBeGreaterThanOrEqual(1)

    // Empresa: TODAS las empresas del sistema (SPEC-043) + "+ Nueva empresa"
    await user.click(within(sheet).getByRole('combobox', { name: 'Empresa' }))
    expect(await screen.findByRole('option', { name: 'Acme Corp' })).toBeInTheDocument()
    expect(screen.getByRole('option', { name: '+ Nueva empresa' })).toBeInTheDocument()
    expect(vi.mocked(mockApi.api.db.listCompanies)).toHaveBeenCalledWith()
    await user.click(screen.getByRole('option', { name: 'Acme Corp' }))

    // Con empresa existente elegida: "Sin contacto" + contactos + "+ Nuevo contacto"
    const enabledContactSelect = within(sheet).getByRole('combobox', { name: 'Contacto' })
    await waitFor(() => expect(enabledContactSelect).toBeEnabled())
    await user.click(enabledContactSelect)
    expect(await screen.findByRole('option', { name: 'Sin contacto' })).toBeInTheDocument()
    expect(screen.getByRole('option', { name: 'Jane Doe' })).toBeInTheDocument()
    expect(screen.getByRole('option', { name: '+ Nuevo contacto' })).toBeInTheDocument()
    expect(vi.mocked(mockApi.api.db.listContacts)).toHaveBeenCalledWith('c-1')
  })

  // SPEC-020 · AC-24
  it('shows the inline Nombre/Website/LinkedIn fields when "+ Nueva empresa" is selected, without a second modal', async () => {
    const user = userEvent.setup()
    renderSheet()

    await chooseCompany(user, '+ Nueva empresa')

    const sheet = await findSheet()
    expect(within(sheet).getByLabelText('Nombre')).toBeInTheDocument()
    expect(within(sheet).getByLabelText('Website')).toBeInTheDocument()
    expect(within(sheet).getByLabelText('LinkedIn')).toBeInTheDocument()
    // Sigue siendo el mismo Sheet: no se abre un segundo dialog
    expect(screen.getAllByRole('dialog')).toHaveLength(1)

    // Con empresa NUEVA el contacto solo ofrece "Sin contacto" y "+ Nuevo contacto"
    await user.click(within(sheet).getByRole('combobox', { name: 'Contacto' }))
    expect(await screen.findByRole('option', { name: 'Sin contacto' })).toBeInTheDocument()
    expect(screen.getByRole('option', { name: '+ Nuevo contacto' })).toBeInTheDocument()
    expect(screen.queryByRole('option', { name: 'Jane Doe' })).not.toBeInTheDocument()
  })

  // SPEC-020 · AC-25
  it('shows the inline Nombre/Posición/LinkedIn fields when "+ Nuevo contacto" is selected', async () => {
    const user = userEvent.setup()
    renderSheet()

    await chooseCompany(user, 'Acme Corp')
    const sheet = await findSheet()
    await user.click(within(sheet).getByRole('combobox', { name: 'Contacto' }))
    await user.click(await screen.findByRole('option', { name: '+ Nuevo contacto' }))

    expect(within(sheet).getByLabelText('Nombre')).toBeInTheDocument()
    expect(within(sheet).getByLabelText('Posición')).toBeInTheDocument()
    expect(within(sheet).getByLabelText('LinkedIn')).toBeInTheDocument()
  })

  // SPEC-020 · AC-26
  it('shows the inline "Campo requerido" error and persists nothing when the new company name is empty', async () => {
    const user = userEvent.setup()
    renderSheet()

    await chooseCompany(user, '+ Nueva empresa')
    const sheet = await findSheet()
    await user.click(within(sheet).getByRole('button', { name: 'Asignar' }))

    expect(await within(sheet).findByText('Campo requerido')).toBeInTheDocument()
    expect(vi.mocked(mockApi.api.db.assignInterviewCompany)).not.toHaveBeenCalled()
    expect(onAssigned).not.toHaveBeenCalled()
  })

  // SPEC-020 · AC-28 (renderer: UNA sola operación compuesta con los datos inline)
  it('assigns creating the new company and contact in a single bridge operation and notifies the assignment', async () => {
    const assigned: AssignCompanyResult = {
      interview: { ...INTERVIEW, companyId: 'c-9', contactIds: ['ct-9'] },
      company: { ...COMPANY, id: 'c-9', name: 'Globex' },
      contact: { ...CONTACT, id: 'ct-9', companyId: 'c-9', name: 'John Smith' }
    }
    vi.mocked(mockApi.api.db.assignInterviewCompany).mockResolvedValue({
      ok: true,
      data: assigned
    })
    const user = userEvent.setup()
    renderSheet()

    await chooseCompany(user, '+ Nueva empresa')
    const sheet = await findSheet()
    await user.type(within(sheet).getByLabelText('Nombre'), 'Globex')
    await user.click(within(sheet).getByRole('combobox', { name: 'Contacto' }))
    await user.click(await screen.findByRole('option', { name: '+ Nuevo contacto' }))
    // Tras elegir "+ Nuevo contacto" hay dos grupos de campos inline: el del
    // contacto es el segundo "Nombre"
    const nameInputs = within(sheet).getAllByLabelText('Nombre')
    await user.type(nameInputs[1], 'John Smith')
    await user.click(within(sheet).getByRole('button', { name: 'Asignar' }))

    await waitFor(() =>
      expect(vi.mocked(mockApi.api.db.assignInterviewCompany)).toHaveBeenCalledWith('i-1', {
        newCompany: { name: 'Globex', website: null, linkedinUrl: null },
        newContact: { name: 'John Smith', position: null, linkedinUrl: null }
      })
    )
    expect(vi.mocked(mockApi.api.db.assignInterviewCompany)).toHaveBeenCalledTimes(1)
    expect(onAssigned).toHaveBeenCalledWith(assigned)
    expect((await screen.findAllByText('Empresa asignada')).length).toBeGreaterThanOrEqual(1)
    expect(onOpenChange).toHaveBeenCalledWith(false)
  })

  // SPEC-020 · AC-30
  it('keeps the Sheet open with a destructive toast and no half-applied state when the bridge fails', async () => {
    vi.mocked(mockApi.api.db.assignInterviewCompany).mockResolvedValue({
      ok: false,
      error: { kind: 'storage', message: 'Fallo simulado al asignar' }
    })
    const user = userEvent.setup()
    renderSheet()

    await chooseCompany(user, 'Acme Corp')
    const sheet = await findSheet()
    await user.click(within(sheet).getByRole('button', { name: 'Asignar' }))

    expect((await screen.findAllByText('Fallo simulado al asignar')).length).toBeGreaterThanOrEqual(
      1
    )
    // El Sheet permanece abierto con el formulario intacto
    expect(screen.getByTestId('assign-company-sheet')).toBeInTheDocument()
    expect(within(sheet).getByRole('combobox', { name: 'Empresa' })).toHaveTextContent('Acme Corp')
    expect(onAssigned).not.toHaveBeenCalled()
    expect(onOpenChange).not.toHaveBeenCalledWith(false)
    // Y se puede reintentar: el botón vuelve a estar habilitado
    await waitFor(() =>
      expect(within(sheet).getByRole('button', { name: 'Asignar' })).toBeEnabled()
    )
  })
})
